// ─────────────────────────────────────────────────────────────────────────────
// Normalise (AliExpress affiliate product → products shape)
// Mirrors the Amazon/eBay Normalise contract: emits { valid, product, ... } plus a
// top-level 'asin' alias (= product_id) so every reused downstream node that reads
// norm.asin / norm.imageUrl / norm.product keeps working unchanged.
// ─────────────────────────────────────────────────────────────────────────────
const cfg = $('Config').first().json;
const inp = $input.first().json; // { product_id, p } from Fetch Product Detail
const productId = String(inp.product_id || '');
const p = inp.p || {};

const fail = (reason) => [{ json: { valid: false, skipReason: reason, asin: productId, productId } }];

if (!productId) return fail('no product_id');
const name = p.product_title || p.subject || p.title;
if (!name) return fail('product has no title');

// ── Helpers ───────────────────────────────────────────────────────────────────
const slugify = (s) => String(s || '').toLowerCase().normalize('NFKD').replace(/[\u0300-\u036f]/g, '').replace(/[^a-z0-9]+/g, '-').replace(/^-+|-+$/g, '').slice(0, 80);
const clamp = (n, lo, hi) => Math.max(lo, Math.min(hi, n));
const round2 = (n) => Math.round(n * 100) / 100;
const parsePrice = (v) => { if (v == null) return null; if (typeof v === 'number') return v; const m = String(v).replace(/,/g, '').match(/[\d]+(?:\.[\d]+)?/); return m ? Number(m[0]) : null; };
const httpsify = (u) => { if (!u) return null; let s = String(u).trim(); if (s.startsWith('//')) s = 'https:' + s; else if (s.startsWith('http://')) s = 'https://' + s.slice(7); return s; };
const CURRENCIES = ['USD', 'GBP', 'EUR', 'CAD', 'AUD'];

// ── Currency ────────────────────────────────────────────────────────────────
let currency = p.target_sale_price_currency || p.sale_price_currency || cfg.aliTargetCurrency || 'USD';
if (!CURRENCIES.includes(currency)) currency = 'USD';

// ── Price (+ first-valid-price fallback, shared across the loop) ──────────────
let price = parsePrice(p.target_sale_price != null ? p.target_sale_price : p.sale_price);
let originalPrice = parsePrice(p.target_original_price != null ? p.target_original_price : p.original_price);
let discountPct = 0;
if (p.discount != null) { const m = String(p.discount).match(/(\d+)/); if (m) discountPct = Math.round(Number(m[1])); }
let priceFallback = false;

const store = $getWorkflowStaticData('global');
if (store.priceRunId !== $execution.id) { store.priceRunId = $execution.id; store.firstValidPrice = null; store.firstValidCurrency = null; }
if (price != null) {
  if (store.firstValidPrice == null) { store.firstValidPrice = price; store.firstValidCurrency = currency; }
} else if (store.firstValidPrice != null) {
  price = store.firstValidPrice; currency = store.firstValidCurrency || currency; originalPrice = null; discountPct = 0; priceFallback = true;
  console.log(JSON.stringify({ event: 'price_fallback', asin: productId, borrowedPrice: price, currency, ts: new Date().toISOString() }));
} else {
  return fail('price_unresolved_no_fallback');
}
if (!priceFallback && !discountPct && price && originalPrice && originalPrice > price) {
  discountPct = Math.round(((originalPrice - price) / originalPrice) * 100);
}

// ── Affiliate URL (prefer the tracked promotion_link) ─────────────────────────
const affiliateUrl = httpsify(p.promotion_link) || httpsify(p.product_detail_url);
if (!affiliateUrl || !affiliateUrl.startsWith('https://')) return fail('affiliate_url missing/non-https');
if (!p.promotion_link) {
  console.warn(JSON.stringify({ event: 'affiliate_url_not_tracked', asin: productId, note: 'set aliTrackingId + enrol AliExpress affiliate to get a tracked promotion_link', ts: new Date().toISOString() }));
}

// ── Image ─────────────────────────────────────────────────────────────────────
let small = p.product_small_image_urls;
if (small && small.string) small = small.string;
const firstSmall = Array.isArray(small) ? small[0] : small;
const imageUrl = httpsify(p.product_main_image_url || firstSmall);
if (!imageUrl) return fail('no image URL');

// ── Brand (affiliate API has no brand → first word of title, like Amazon/eBay) ─
let brand = (typeof name === 'string' ? name.split(/\s+/)[0] : '') || 'AliExpress';

// ── Seller + condition (reused DB columns) ────────────────────────────────────
const seller = (p.shop_name || p.store_name) ? String(p.shop_name || p.store_name).slice(0, 120) : null;
const condition = 'New'; // AliExpress lists new goods

// ── Rating: evaluate_rate "90.5%" → 0..5 ──────────────────────────────────────
let rating = 0;
if (p.evaluate_rate != null) { const m = String(p.evaluate_rate).match(/[\d.]+/); if (m) rating = Math.round(clamp(Number(m[0]) / 20, 0, 5) * 10) / 10; }
else if (p.avg_evaluation_rating != null) { rating = Math.round(clamp(Number(p.avg_evaluation_rating), 0, 5) * 10) / 10; }

// ── Tags / slug / image key ───────────────────────────────────────────────────
const tags = [p.first_level_category_name, p.second_level_category_name].map((s) => String(s || '').trim()).filter(Boolean);
const shortDesc = String(name).slice(0, 200);
const slug = slugify(name) + '-' + productId.toLowerCase();
const title = String(name).slice(0, 120);
const imageKey = 'products/aliexpress/' + productId + '/main.jpg';

console.log(JSON.stringify({ event: 'url_validated', asin: productId, affiliate_url: affiliateUrl, tracked: !!p.promotion_link, ts: new Date().toISOString() }));

return [{
  json: {
    valid: true, skipReason: null, priceFallback,
    asin: productId, productId,
    slug, imageUrl, imageKey, imageDim: 800, imageAlt: title,
    product: {
      slug,
      title,
      brand: String(brand || '').slice(0, 80),
      short_description: shortDesc,
      description: '',
      price: round2(price),
      original_price: originalPrice != null ? round2(originalPrice) : null,
      currency,
      discount_percent: discountPct,
      deal_label: null,
      affiliate_source: 'aliexpress',
      amazon_affiliate_tag: null,
      affiliate_url: affiliateUrl,
      seller,
      condition,
      rating,
      features: [],
      tags,
      pros: [],
      cons: [],
      subcategory_id: null,
      seo_title: null,
      seo_description: null,
      seo_og_image: null,
      expires_at: null,
    },
  },
}];

// Log Skipped Item (v3.1) — audit trail for items the workflow skips.
// Reached only on the FALSE branch of 'Is Valid?' (unavailable, no price to borrow,
// no brand, no image, bad URL, etc.). Connects back to Loop Over Items so the run
// continues to the next ASIN instead of terminating.
const item = $input.first().json;
const entry = {
  event:  'item_skipped',
  asin:   item.asin ?? null,
  reason: item.skipReason ?? 'unknown',
  ts:     new Date().toISOString(),
};
console.log(JSON.stringify(entry));
return [{ json: { ...item, _skipped: true, _log: entry } }];

// ── AI Gate Decision ─────────────────────────────────────────────────────────
// Reads the DB check result and the overrideAiFields config flag.
// Sets skipAi=true when all 5 AI fields are already populated AND override is off.
const cfg    = $('Config').first().json;
const norm   = $('Is Valid?').first().json;
const dbRows = $input.all();     // 0 rows = new product, 1 row = existing

const override = cfg.overrideAiFields === true;

let allPopulated = false;
if (dbRows.length > 0) {
  const r = dbRows[0].json;
  allPopulated = r.has_subcategory_id && r.has_pros && r.has_cons && r.has_seo_title && r.has_seo_description;
}

const skipAi = allPopulated && !override;

console.log(JSON.stringify({
  event: 'ai_gate', asin: norm.asin,
  allPopulated, override, skipAi,
  ts: new Date().toISOString(),
}));

return [{ json: { ...norm, skipAi } }];

// ─────────────────────────────────────────────────────────────────────────────
// Build AI Enrichment Request
// Single OpenRouter call for: subcategory name, pros[], cons[], seo_title, seo_description.
// subcategory is sent as a NAME here; resolved to a uuid in Parse & Validate AI Fields.
// ─────────────────────────────────────────────────────────────────────────────
const cfg     = $('Config').first().json;
const norm    = $input.first().json;
const product = norm.product;

// Build the list of available subcategory names for the prompt
const subcatRows = $('Fetch Subcategories').all().map(i => i.json);
const subcatNames = subcatRows
  .filter(r => r?.name)
  .map(r => String(r.name).trim())
  .slice(0, 80);    // cap prompt length

const featureBullets = Array.isArray(product.features) ? product.features : [];
const tags           = Array.isArray(product.tags)     ? product.tags     : [];

const productContext = [
  `Title: ${product.title}`,
  `Brand: ${product.brand}`,
  product.condition ? `Condition: ${product.condition}` : null,
  product.short_description ? `Short description: ${product.short_description}` : null,
  product.description       ? `Full description: ${String(product.description).slice(0,500)}` : null,
  featureBullets.length     ? `Key features:\n${featureBullets.slice(0,8).map(f=>`- ${f}`).join('\n')}` : null,
  tags.length               ? `Category breadcrumbs: ${tags.slice(0,5).join(' > ')}` : null,
  `Price: ${product.currency} ${product.price}`,
  product.original_price    ? `Original price: ${product.currency} ${product.original_price}` : null,
  product.rating            ? `Average rating: ${product.rating}/5` : null,
].filter(Boolean).join('\n');

const subcatSection = subcatNames.length
  ? `Available subcategories (choose the single best fit; use exact spelling):\n${subcatNames.map(n=>`- ${n}`).join('\n')}`
  : 'No subcategory list available — infer the most appropriate retail subcategory name.';

const systemPrompt = [
  'You are a product data enrichment assistant for an affiliate e-commerce site.',
  'Return ONLY this JSON object — no prose, no markdown fences:',
  '{',
  '  "subcategory": "<exact name from the list, or best-fit retail subcategory>",',
  '  "pros": ["<advantage 1>", "<advantage 2>", "<advantage 3>"],',
  '  "cons": ["<disadvantage 1>", "<disadvantage 2>", "<disadvantage 3>"],',
  '  "seo_title": "<keyword-rich title, HARD MAX 60 characters>",',
  '  "seo_description": "<meta description, HARD MAX 160 characters, include primary keyword>"',
  '}',
  '',
  'RULES:',
  '- pros and cons: 3 to 5 items each; each item max 120 characters.',
  '- seo_title: truncate to 60 chars if needed — never exceed.',
  '- seo_description: truncate to 160 chars if needed — never exceed.',
  '- subcategory: use the exact spelling from the provided list when possible.',
  '- Output the JSON object only.',
].join('\n');

const requestBody = {
  model:       cfg.openrouterModel,
  messages: [
    { role: 'system', content: systemPrompt },
    { role: 'user',   content: `${subcatSection}\n\nProduct details:\n${productContext}` },
  ],
  temperature: 0.3,
  max_tokens:  700,
};

console.log(JSON.stringify({ event: 'ai_enrichment_built', asin: norm.asin, subcatCount: subcatNames.length, ts: new Date().toISOString() }));

return [{ json: { requestBody, normData: norm } }];

// ─────────────────────────────────────────────────────────────────────────────
// Parse & Validate AI Fields  v2
//
// DB schema truth:
//   pros         → text[]   (stored as jsonb array in payload, cast in upsert)
//   cons         → text[]   (same)
//   subcategory_id → uuid   (AI returns a name; we resolve to UUID here)
//   seo_title    → text     (enforced ≤ 60 chars)
//   seo_description → text  (enforced ≤ 160 chars)
// ─────────────────────────────────────────────────────────────────────────────
const SEO_TITLE_MAX      = 60;
const SEO_DESC_MAX       = 160;
const ITEM_MAX           = 120;   // max chars per pros/cons bullet
const MIN_ITEMS          = 3;
const MAX_ITEMS          = 5;

const aiRes  = $input.first().json;
const req    = $('Build AI Enrichment Request').first().json;
const norm   = req.normData;

// ── Subcategory lookup table (name → uuid) ────────────────────────────────────
const subcatRows = $('Fetch Subcategories').all().map(i => i.json);
const nameToSubcatId = new Map();
for (const r of subcatRows) {
  if (r?.id && r?.name) nameToSubcatId.set(String(r.name).trim().toLowerCase(), r.id);
}

function resolveSubcatId(aiName) {
  if (!aiName || typeof aiName !== 'string') return null;
  const key = aiName.trim().toLowerCase();
  // 1. Exact match (case-insensitive)
  if (nameToSubcatId.has(key)) return nameToSubcatId.get(key);
  // 2. Starts-with match (handles minor suffix differences)
  for (const [k, id] of nameToSubcatId) {
    if (k.startsWith(key) || key.startsWith(k)) return id;
  }
  // 3. Contains match as last resort
  for (const [k, id] of nameToSubcatId) {
    if (k.includes(key) || key.includes(k)) return id;
  }
  return null;   // no match → column stays null
}

// ── Rate-limit guard ──────────────────────────────────────────────────────────
if (aiRes?.error?.code === 429 || aiRes?.statusCode === 429) {
  console.warn(JSON.stringify({ event:'ai_rate_limited', asin: norm.asin, ts: new Date().toISOString() }));
  return [{ json: { ...norm, _aiStatus: 'rate_limited' } }];
}

// ── HTTP / API error guard ────────────────────────────────────────────────────
// neverError:true swallows non-2xx responses; surface them loudly instead of
// silently emitting empty AI fields. A 401 here = the OpenRouter credential is
// not selected on the 'Call OpenRouter (AI Enrichment)' node (see n8n/README.md).
if (aiRes && aiRes.error) {
  const code = aiRes.error.code ?? 'unknown';
  console.warn(JSON.stringify({ event:'ai_http_error', asin: norm.asin, code, message: String(aiRes.error.message || '').slice(0,200), ts: new Date().toISOString() }));
  return [{ json: { ...norm, _aiStatus: `http_error_${code}` } }];
}

// ── Extract raw content string ────────────────────────────────────────────────
function getContent(r) {
  const str = r?.choices?.[0]?.message?.content;
  if (typeof str === 'string' && str.trim()) return str;
  if (Array.isArray(str)) return str.filter(x=>x?.type==='text').map(x=>x.text).join('');
  return r?.choices?.[0]?.text ?? null;
}

// ── Loose JSON parser ─────────────────────────────────────────────────────────
function parseLoose(text) {
  if (!text) return null;
  try { return JSON.parse(text); } catch {}
  const f = text.match(/```(?:json)?\s*([\s\S]*?)```/);
  if (f) { try { return JSON.parse(f[1]); } catch {} }
  const a = text.indexOf('{'), b = text.lastIndexOf('}');
  if (a >= 0 && b > a) { try { return JSON.parse(text.slice(a, b+1)); } catch {} }
  return null;
}

// ── Sanitise helpers ──────────────────────────────────────────────────────────
// Remove ASCII control chars (except tab/newline), trim.
const sanitise = (s) => String(s || '').replace(/[\x00-\x08\x0B\x0C\x0E-\x1F]/g, '').trim();
const trunc    = (s, n) => sanitise(s).slice(0, n);

// Validate + sanitise a text[] array field.
// Returns an array of strings, clipped to [MIN_ITEMS..MAX_ITEMS] items.
function normArray(arr) {
  if (!Array.isArray(arr)) return [];
  return arr
    .map(x => trunc(String(x ?? ''), ITEM_MAX))
    .filter(Boolean)
    .slice(0, MAX_ITEMS);
}

// ── Parse response ────────────────────────────────────────────────────────────
const content = getContent(aiRes);
const parsed  = parseLoose(content);

let aiStatus        = 'success';
let subcategoryName = null;
let subcategory_id  = null;
let pros            = [];
let cons            = [];
let seo_title       = null;
let seo_description = null;

if (!parsed) {
  aiStatus = 'parse_failed';
  console.warn(JSON.stringify({ event:'ai_parse_failed', asin: norm.asin, head: String(content||'').slice(0,300), ts: new Date().toISOString() }));
} else {
  // subcategory: resolve name → UUID
  subcategoryName = sanitise(parsed.subcategory || '');
  subcategory_id  = resolveSubcatId(subcategoryName) ?? null;
  if (!subcategory_id && subcategoryName) aiStatus = 'subcategory_unresolved';

  // pros / cons → text[] (stored as JSON arrays in payload, converted to pg text[] in upsert)
  pros = normArray(parsed.pros);
  cons = normArray(parsed.cons);
  if (pros.length < MIN_ITEMS) aiStatus = aiStatus === 'success' ? 'partial_pros' : aiStatus;
  if (cons.length < MIN_ITEMS) aiStatus = aiStatus === 'success' ? 'partial_cons' : aiStatus;

  // seo fields
  seo_title       = trunc(parsed.seo_title       || '', SEO_TITLE_MAX)  || null;
  seo_description = trunc(parsed.seo_description || '', SEO_DESC_MAX)   || null;
  if (!seo_title)       aiStatus = 'missing_seo_title';
  if (!seo_description) aiStatus = aiStatus === 'success' ? 'missing_seo_description' : aiStatus;
}

console.log(JSON.stringify({
  event:           'ai_enrichment_parsed',
  asin:            norm.asin,
  aiStatus,
  subcategoryName,
  subcategory_id,
  seo_title_len:   seo_title?.length ?? 0,
  seo_desc_len:    seo_description?.length ?? 0,
  pros_count:      pros.length,
  cons_count:      cons.length,
  ts:              new Date().toISOString(),
}));

return [{
  json: {
    ...norm,
    product: {
      ...norm.product,
      subcategory_id,    // uuid | null
      pros,              // string[] (maps to text[] via jsonb_array_elements_text in upsert)
      cons,              // string[] (same)
      seo_title,         // string | null — max 60
      seo_description,   // string | null — max 160
    },
    _aiStatus: aiStatus,
  },
}];

// Bypass branch — AI fields already populated in DB; pass norm data unchanged.
const norm = $input.first().json;
console.log(JSON.stringify({ event:'ai_skipped', asin: norm.asin, ts: new Date().toISOString() }));
return [{ json: { ...norm, _aiStatus: 'skipped_already_populated' } }];

// Build OpenRouter category classification request — unchanged from v1 logic.
const cfg = $('Config').first().json;
const categoriesRows = $('Fetch Categories').all().map(i => i.json);
const norm = $input.first().json;

if (categoriesRows.length === 0) {
  return [{ json: { skip: true, reason: 'no_categories_in_db', labelMap: [], normPassthrough: norm } }];
}

const labelToId = new Map();
const lines = [];
for (const c of categoriesRows) {
  if (!c?.id || !c?.name) continue;
  let label = String(c.name).trim();
  let suffix = 2;
  while (labelToId.has(label)) label = `${c.name} #${suffix++}`;
  labelToId.set(label, c.id);
  const desc = c.description ? ` — ${String(c.description).slice(0,140)}` : '';
  lines.push(`- ${label}${desc}`);
}

const product = norm.product;
const productContext = [
  `Title: ${product.title}`,
  `Brand: ${product.brand}`,
  product.short_description ? `Description: ${product.short_description}` : null,
  product.tags?.length      ? `Tags: ${product.tags.slice(0,8).join(', ')}` : null,
  product.features?.length  ? `Key features: ${product.features.slice(0,3).join('; ')}` : null,
].filter(Boolean).join('\n');

const systemPrompt = [
  'You are a product categorization assistant for an affiliate deals website.',
  'Given a product and a list of categories, return your TOP THREE most likely categories ranked by fit.',
  'RESPOND WITH ONLY THIS JSON OBJECT — no prose, no code fences:',
  '{"rankings":[{"category":"<exact name from list>","confidence":<0.0-1.0>,"reasoning":"<one short sentence>"}]}',
  'RULES:',
  '- "category" MUST be copied verbatim from the list (text after "- ", before any —).',
  '- Up to 3 rankings, descending confidence. Minimum 1.',
  '- If NO category fits return {"rankings":[]}.',
  '- Output JSON only.',
].join('\n');

const requestBody = {
  model:    cfg.openrouterModel,
  messages: [
    { role: 'system', content: systemPrompt },
    { role: 'user',   content: `Available categories:\n${lines.join('\n')}\n\nProduct:\n${productContext}` },
  ],
  temperature: 0,
  max_tokens:  400,
};

return [{ json: { requestBody, labelMap: Array.from(labelToId.entries()), normPassthrough: norm } }];

// Resolve OpenRouter classifier response → category_id uuid.
const cfg = $('Config').first().json;
const res = $input.first().json;
const req = $('Build Classifier Request').first().json;
const norm = req.normPassthrough;

const threshold = Number(cfg.classifierConfidenceThreshold) || 0.6;
const labelToId = new Map(Array.isArray(req?.labelMap) ? req.labelMap : []);

function extractContent(r) {
  if (!r || typeof r !== 'object') return { content: null, shape: `non-object:${typeof r}` };
  const str = r?.choices?.[0]?.message?.content;
  if (typeof str === 'string' && str.trim()) return { content: str, shape: 'string' };
  if (Array.isArray(str)) {
    const t = str.filter(x=>x?.type==='text').map(x=>x.text).join('');
    if (t.trim()) return { content: t, shape: 'parts' };
  }
  const legacy = r?.choices?.[0]?.text;
  if (typeof legacy === 'string' && legacy.trim()) return { content: legacy, shape: 'legacy' };
  return { content: null, shape: `keys=[${Object.keys(r).join(',')}] err=${JSON.stringify(r?.error??null).slice(0,200)}` };
}

function parseLoose(text) {
  if (typeof text !== 'string') return { value: null, how: 'no-text' };
  try { return { value: JSON.parse(text), how: 'direct' }; } catch {}
  const f = text.match(/```(?:json)?\s*([\s\S]*?)```/);
  if (f) { try { return { value: JSON.parse(f[1]), how: 'fenced' }; } catch {} }
  const a = text.indexOf('{'), b = text.lastIndexOf('}');
  if (a >= 0 && b > a) { try { return { value: JSON.parse(text.slice(a, b+1)), how: 'substr' }; } catch {} }
  return { value: null, how: 'failed' };
}

function resolve() {
  if (res?.skip)  return { id: cfg.defaultCategoryId, status: `fallback_${res.reason}`,           confidence: 0, note: 'no categories' };
  if (res?.error) return { id: cfg.defaultCategoryId, status: 'fallback_api_error',               confidence: 0, note: String(res.error?.message||'') };
  const { content, shape } = extractContent(res);
  if (!content)   return { id: cfg.defaultCategoryId, status: 'fallback_empty_response',          confidence: 0, note: shape };
  const { value: parsed, how } = parseLoose(content);
  if (!parsed)    return { id: cfg.defaultCategoryId, status: 'fallback_parse_error',             confidence: 0, note: `${how}: ${content.slice(0,120)}` };
  const rankings = Array.isArray(parsed?.rankings) ? parsed.rankings : [];
  if (!rankings.length) return { id: cfg.defaultCategoryId, status: 'fallback_no_rankings',      confidence: 0, note: `parse:${how}` };
  const missed = [];
  for (let i = 0; i < rankings.length; i++) {
    const cand  = rankings[i];
    const label = cand?.category ?? cand?.categoryId;
    const conf  = Number(cand?.confidence);
    if (!label || typeof label !== 'string') { missed.push(`r${i+1}:missing`); continue; }
    const realId = labelToId.get(label.trim());
    if (!realId) { missed.push(`r${i+1}:"${label}"`); continue; }
    if (!Number.isFinite(conf) || conf < threshold) {
      return { id: cfg.defaultCategoryId, status: 'fallback_low_confidence', confidence: conf||0, note: `"${label}" conf=${conf}<${threshold}` };
    }
    return { id: realId, status: i === 0 ? 'classified' : `fallback_rank_${i+1}`, confidence: conf, note: `"${label}"→${realId}` };
  }
  return { id: cfg.defaultCategoryId, status: 'fallback_hallucinated', confidence: 0, note: `all invalid:[${missed.join(',')}]` };
}

const r = resolve();
console.log(JSON.stringify({ event:'category_resolved', asin: norm.asin, status: r.status, confidence: r.confidence, note: r.note, ts: new Date().toISOString() }));

return [{
  json: {
    ...norm,
    product: { ...norm.product, category_id: r.id },
    _classifier: { status: r.status, confidence: r.confidence, note: r.note },
  },
}];

// Audit Log — structured JSON per product for debugging / monitoring.
const upsert  = $input.first().json;
const payload = $('Build Payload').first().json;

const entry = {
  event:        'product_upserted',
  id:           upsert.id,
  slug:         upsert.slug,
  was_inserted: upsert.was_inserted,
  ai_status:    payload._aiStatus,
  classifier:   payload._classifier,
  ts:           new Date().toISOString(),
};

console.log(JSON.stringify(entry));
return [{ json: { ...upsert, _log: entry } }];

// ─────────────────────────────────────────────────────────────────────────────
// Search AliExpress Hot Products — signed aliexpress.affiliate.hotproduct.query.
// Replaces the eBay OAuth + Browse search + Extract Items trio. Discovers active hot
// deals, dedups by product_id, caps at maxDealsPerRun, and emits one item per product
// for Loop Over Items. The hotproduct.query summary already carries title / prices /
// promotion_link / image, so Fetch Product Detail only enriches it.
// ─────────────────────────────────────────────────────────────────────────────
let nodeCrypto;
try {
  nodeCrypto = require('crypto');
} catch (e) {
  throw new Error('Code node cannot require("crypto") — set NODE_FUNCTION_ALLOW_BUILTIN=crypto (or *) in the n8n environment and restart. It is required to sign AliExpress API requests.');
}

const cfg = $('Config').first().json;
const gateway = String(cfg.aliGatewayUrl || 'https://api-sg.aliexpress.com/sync').trim();
const appKey = String(cfg.aliAppKey || '').trim();
const appSecret = String(cfg.aliAppSecret || '').trim();
const trackingId = String(cfg.aliTrackingId || '').trim();
const signMethod = (String(cfg.aliSignMethod || 'sha256').toLowerCase() === 'md5') ? 'md5' : 'sha256';
const maxDeals = Math.max(1, Number(cfg.maxDealsPerRun) || 5);
const pageSize = Math.max(maxDeals, Math.min(50, Number(cfg.aliPageSize) || 50));

if (!appKey || !appSecret) {
  throw new Error('AliExpress config missing: set aliAppKey + aliAppSecret in the Config node.');
}
if (!trackingId) {
  console.warn(JSON.stringify({ event: 'ali_no_tracking_id', note: 'aliTrackingId empty → promotion_link will be missing; affiliate_url falls back to product_detail_url', ts: new Date().toISOString() }));
}

// timestamp: epoch-ms for the api-sg .../sync gateway (default), or "yyyy-MM-dd HH:mm:ss"
// in GMT+8 for the legacy gw.api.taobao.com/router/rest gateway (set aliTimestampFormat=datetime).
function tsStr() {
  if (String(cfg.aliTimestampFormat || 'ms').toLowerCase() === 'datetime') {
    const t = new Date(Date.now() + 8 * 3600 * 1000);
    const z = (n) => String(n).padStart(2, '0');
    return t.getUTCFullYear() + '-' + z(t.getUTCMonth() + 1) + '-' + z(t.getUTCDate()) + ' ' + z(t.getUTCHours()) + ':' + z(t.getUTCMinutes()) + ':' + z(t.getUTCSeconds());
  }
  return String(Date.now());
}

// TOP/IOP signing: sort params by key, concatenate key+value (raw, un-encoded).
//   md5    → MD5(secret + concat + secret), uppercase hex
//   sha256 → HMAC-SHA256(concat) keyed by secret, uppercase hex
function sign(params, secret, method) {
  const concat = Object.keys(params).sort().map((k) => k + params[k]).join('');
  if (method === 'md5') {
    return nodeCrypto.createHash('md5').update(secret + concat + secret, 'utf8').digest('hex').toUpperCase();
  }
  return nodeCrypto.createHmac('sha256', secret).update(concat, 'utf8').digest('hex').toUpperCase();
}

const params = {
  method: 'aliexpress.affiliate.hotproduct.query',
  app_key: appKey,
  sign_method: signMethod,
  timestamp: tsStr(),
  format: 'json',
  v: String(cfg.aliApiVersion || '2.0'),
  simplify: 'true',
  page_no: '1',
  page_size: String(pageSize),
  target_currency: String(cfg.aliTargetCurrency || 'USD'),
  target_language: String(cfg.aliTargetLanguage || 'EN'),
  ship_to_country: String(cfg.aliShipToCountry || 'US'),
};
if (trackingId) params.tracking_id = trackingId;
if (cfg.aliCategoryIds) params.category_ids = String(cfg.aliCategoryIds);
if (cfg.aliKeywords) params.keywords = String(cfg.aliKeywords);
if (cfg.aliSort) params.sort = String(cfg.aliSort);

params.sign = sign(params, appSecret, signMethod);

// Sign over RAW values; send URL-encoded values (the gateway decodes before verifying).
const body = Object.keys(params).map((k) => encodeURIComponent(k) + '=' + encodeURIComponent(params[k])).join('&');

const tip = ' Tips: a signature error ("IncompleteSignature"/"Sign check"/"Invalid signature") → try aliSignMethod=md5 or aliTimestampFormat=datetime, and re-check aliAppKey/aliAppSecret; a permission error → aliexpress.affiliate.hotproduct.query needs extra approval (fallback: aliexpress.affiliate.product.query).';

let resp;
try {
  resp = await this.helpers.httpRequest({
    method: 'POST',
    url: gateway,
    headers: { 'Content-Type': 'application/x-www-form-urlencoded', 'Accept': 'application/json' },
    body,
    returnFullResponse: true,
    timeout: 120000,
  });
} catch (err) {
  const r = (err && err.response) || {};
  const b = (r.data !== undefined) ? r.data : (r.body !== undefined ? r.body : (err.message || String(err)));
  throw new Error('AliExpress hotproduct.query HTTP failure: ' + (typeof b === 'string' ? b : JSON.stringify(b)).slice(0, 300));
}

let data = resp.body;
if (typeof data === 'string') { try { data = JSON.parse(data); } catch (e) { data = {}; } }

// TOP error envelope
if (data && data.error_response) {
  const e = data.error_response;
  throw new Error('AliExpress API error ' + (e.code || '') + '/' + (e.sub_code || '') + ': ' + String(e.sub_msg || e.msg || JSON.stringify(e)).slice(0, 300) + '.' + tip);
}
// IOP error envelope
if (data && data.code !== undefined && String(data.code) !== '0' && (data.message || data.type)) {
  throw new Error('AliExpress IOP error ' + data.code + ': ' + String(data.message || data.type).slice(0, 300) + '.' + tip);
}

// Locate resp_result / result anywhere in the (possibly simplified) envelope.
function deepFind(o, key) {
  if (!o || typeof o !== 'object') return undefined;
  if (Object.prototype.hasOwnProperty.call(o, key)) return o[key];
  for (const k of Object.keys(o)) {
    const v = deepFind(o[k], key);
    if (v !== undefined) return v;
  }
  return undefined;
}

const respResult = deepFind(data, 'resp_result');
if (respResult && respResult.resp_code != null && Number(respResult.resp_code) !== 200) {
  throw new Error('AliExpress resp_result ' + respResult.resp_code + ': ' + String(respResult.resp_msg || '').slice(0, 200) + '.' + tip);
}

const result = (respResult && respResult.result) || deepFind(data, 'result') || {};
let products = result.products;
if (products && products.product) products = products.product;
if (!Array.isArray(products)) products = products ? [products] : [];
if (products.length === 0) {
  throw new Error('No products returned by hotproduct.query. Check aliCategoryIds/aliKeywords/aliSort, aliTrackingId, and that the app has hotproduct.query permission.');
}

const seen = new Set();
const items = [];
for (const prod of products) {
  const id = prod && (prod.product_id != null ? String(prod.product_id) : null);
  if (!id || seen.has(id)) continue;
  seen.add(id);
  items.push({ json: { product_id: id, summary: prod } });
  if (items.length >= maxDeals) break;
}
if (items.length === 0) throw new Error('No usable product_ids extracted from hotproduct.query results.');

console.log(JSON.stringify({ event: 'ali_search', total: products.length, selected: items.length, ts: new Date().toISOString() }));

return items;

// ─────────────────────────────────────────────────────────────────────────────
// Fetch Product Detail — signed aliexpress.affiliate.productdetail.get for the
// current loop product. Enriches the hotproduct.query summary with the full product
// object (richer image/category/price fields). SOFT-FAILS to the summary alone if the
// detail call errors, so a single bad detail call never stalls the loop.
// Replaces the eBay "Fetch Item Detail" HTTP node.
// ─────────────────────────────────────────────────────────────────────────────
let nodeCrypto;
try {
  nodeCrypto = require('crypto');
} catch (e) {
  throw new Error('Code node cannot require("crypto") — set NODE_FUNCTION_ALLOW_BUILTIN=crypto (or *) in the n8n environment and restart. It is required to sign AliExpress API requests.');
}

const cfg = $('Config').first().json;
const item = $input.first().json; // { product_id, summary } from Loop Over Items
const productId = String(item.product_id || '');
const summary = item.summary || {};
if (!productId) throw new Error('Fetch Product Detail: missing product_id from the loop item.');

const gateway = String(cfg.aliGatewayUrl || 'https://api-sg.aliexpress.com/sync').trim();
const appKey = String(cfg.aliAppKey || '').trim();
const appSecret = String(cfg.aliAppSecret || '').trim();
const trackingId = String(cfg.aliTrackingId || '').trim();
const signMethod = (String(cfg.aliSignMethod || 'sha256').toLowerCase() === 'md5') ? 'md5' : 'sha256';

function tsStr() {
  if (String(cfg.aliTimestampFormat || 'ms').toLowerCase() === 'datetime') {
    const t = new Date(Date.now() + 8 * 3600 * 1000);
    const z = (n) => String(n).padStart(2, '0');
    return t.getUTCFullYear() + '-' + z(t.getUTCMonth() + 1) + '-' + z(t.getUTCDate()) + ' ' + z(t.getUTCHours()) + ':' + z(t.getUTCMinutes()) + ':' + z(t.getUTCSeconds());
  }
  return String(Date.now());
}

function sign(params, secret, method) {
  const concat = Object.keys(params).sort().map((k) => k + params[k]).join('');
  if (method === 'md5') {
    return nodeCrypto.createHash('md5').update(secret + concat + secret, 'utf8').digest('hex').toUpperCase();
  }
  return nodeCrypto.createHmac('sha256', secret).update(concat, 'utf8').digest('hex').toUpperCase();
}

function deepFind(o, key) {
  if (!o || typeof o !== 'object') return undefined;
  if (Object.prototype.hasOwnProperty.call(o, key)) return o[key];
  for (const k of Object.keys(o)) {
    const v = deepFind(o[k], key);
    if (v !== undefined) return v;
  }
  return undefined;
}

const params = {
  method: 'aliexpress.affiliate.productdetail.get',
  app_key: appKey,
  sign_method: signMethod,
  timestamp: tsStr(),
  format: 'json',
  v: String(cfg.aliApiVersion || '2.0'),
  simplify: 'true',
  product_ids: productId,
  target_currency: String(cfg.aliTargetCurrency || 'USD'),
  target_language: String(cfg.aliTargetLanguage || 'EN'),
  ship_to_country: String(cfg.aliShipToCountry || 'US'),
};
if (trackingId) params.tracking_id = trackingId;
params.sign = sign(params, appSecret, signMethod);
const body = Object.keys(params).map((k) => encodeURIComponent(k) + '=' + encodeURIComponent(params[k])).join('&');

let detail = null;
try {
  const resp = await this.helpers.httpRequest({
    method: 'POST',
    url: gateway,
    headers: { 'Content-Type': 'application/x-www-form-urlencoded', 'Accept': 'application/json' },
    body,
    returnFullResponse: true,
    timeout: 120000,
  });
  let data = resp.body;
  if (typeof data === 'string') { try { data = JSON.parse(data); } catch (e) { data = {}; } }
  if (data && data.error_response) {
    const e = data.error_response;
    console.warn(JSON.stringify({ event: 'ali_detail_error', asin: productId, code: e.code, sub: e.sub_msg || e.sub_code, ts: new Date().toISOString() }));
  } else if (data && data.code !== undefined && String(data.code) !== '0' && (data.message || data.type)) {
    console.warn(JSON.stringify({ event: 'ali_detail_error', asin: productId, code: data.code, sub: String(data.message || data.type).slice(0, 160), ts: new Date().toISOString() }));
  } else {
    const result = deepFind(data, 'result') || {};
    let prods = result.products;
    if (prods && prods.product) prods = prods.product;
    if (!Array.isArray(prods)) prods = prods ? [prods] : [];
    detail = prods[0] || null;
  }
} catch (err) {
  console.warn(JSON.stringify({ event: 'ali_detail_fallback', asin: productId, note: String((err && err.message) || err).slice(0, 200), ts: new Date().toISOString() }));
}

// Merge: detail overrides summary where present; summary guarantees the core fields.
const p = Object.assign({}, summary, detail || {});

console.log(JSON.stringify({ event: 'ali_detail', asin: productId, enriched: !!detail, ts: new Date().toISOString() }));

return [{ json: { product_id: productId, p } }];
